mapper.sql:
WHERE base.SNIPPET_USER_NO = #{snippetUserNo}
  AND base.DEL_YN = 'N'

  AND (
       base.TITLE LIKE CONCAT('%', #{query.q}, '%')
    OR base.SUMMARY LIKE CONCAT('%', #{query.q}, '%')
    OR base.MEMO LIKE CONCAT('%', #{query.q}, '%')

    OR base.SNIPPET_BODY LIKE CONCAT('%', #{query.q}, '%')

  )


  AND base.FOLDER_NO = #{query.folderNo}


  AND EXISTS (
	  SELECT 1
	    FROM snippet.snippet_tag_map filter_map
	   WHERE filter_map.SNIPPET_NO = base.SNIPPET_NO
	     AND filter_map.TAG_NO = #{query.tagNo}
  )


  AND base.LANGUAGE_CD = #{query.languageCd}


  AND base.IS_FAVORITE = #{query.favoriteYn}


  AND base.IS_FAVORITE = 'Y'


  AND base.LAST_VIEWED_DT IS NOT NULL
  AND base.LAST_VIEWED_DT >= DATE_SUB(NOW(), INTERVAL 30 DAY)


  AND base.LAST_COPIED_DT IS NOT NULL
  AND base.LAST_COPIED_DT >= DATE_SUB(NOW(), INTERVAL 30 DAY)


  AND

mapper.insert:
/* SnippetMapper.insertSnippetUser: 신규 스니펫 사용자를 등록 */
INSERT INTO snippet.snippet_user (
       GOOGLE_SUB
     , EMAIL
     , USER_NM
     , PROFILE_IMG_URL
     , LAST_LOGIN_DT
     , USE_YN
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{command.googleSub}
     , #{command.email}
     , #{command.userNm}
     , #{command.profileImgUrl}
     , NOW()
     , 'Y'
     , 'N'
     , #{command.regNo}
     , #{command.udtNo}
)

mapper.update:
/* SnippetMapper.updateSnippetUserAuditNo: 신규 사용자 감사 번호를 사용자 번호 기준으로 갱신 */
UPDATE snippet.snippet_user
   SET REG_NO = #{auditNo}
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}

/* SnippetMapper.updateSnippetUserLoginInfo: 로그인 시 사용자 최신 정보를 갱신 */
UPDATE snippet.snippet_user
   SET EMAIL = #{email}
     , USER_NM = #{userNm}
     , PROFILE_IMG_URL = #{profileImgUrl}
     , LAST_LOGIN_DT = NOW()
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}

mapper.select:
/* SnippetMapper.getRecentViewedSnippetList: 최근 30일 내 조회한 스니펫 목록을 조회 */
SELECT 

 WHERE base.SNIPPET_USER_NO = #{snippetUserNo}
   AND base.DEL_YN = 'N'
   AND base.LAST_VIEWED_DT IS NOT NULL
   AND base.LAST_VIEWED_DT >= DATE_SUB(NOW(), INTERVAL 30 DAY)

 ORDER BY base.LAST_VIEWED_DT DESC, base.SNIPPET_NO DESC
 LIMIT 0, #{limit}

/* SnippetMapper.getRecentCopiedSnippetList: 최근 30일 내 복사한 스니펫 목록을 조회 */
SELECT 

 WHERE base.SNIPPET_USER_NO = #{snippetUserNo}
   AND base.DEL_YN = 'N'
   AND base.LAST_COPIED_DT IS NOT NULL
   AND base.LAST_COPIED_DT >= DATE_SUB(NOW(), INTERVAL 30 DAY)

 ORDER BY base.LAST_COPIED_DT DESC, base.SNIPPET_NO DESC
 LIMIT 0, #{limit}

/* SnippetMapper.countFolderByUserNo: 사용자 소유 폴더 존재 여부를 확인 */
SELECT COUNT(*)
  FROM snippet.snippet_folder
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND FOLDER_NO = #{folderNo}
   AND DEL_YN = 'N'

/* SnippetMapper.countTagByUserNo: 사용자 소유 태그 존재 여부를 확인 */
SELECT COUNT(*)
  FROM snippet.snippet_tag
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND TAG_NO = #{tagNo}
   AND DEL_YN = 'N'

/* SnippetMapper.countLanguageByLanguageCd: 사용 가능한 언어 코드 존재 여부를 확인 */
SELECT COUNT(*)
  FROM snippet.snippet_language
 WHERE LANGUAGE_CD = #{languageCd}
   AND USE_YN = 'Y'

/* SnippetMapper.countOwnedTagList: 사용자 소유 태그 목록 건수를 확인 */
SELECT COUNT(*)
  FROM snippet.snippet_tag
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND DEL_YN = 'N'
   AND TAG_NO IN

	#{tagNo}

/* SnippetMapper.getFolderDuplicateCount: 폴더명 중복 건수를 조회 */
SELECT COUNT(*)
  FROM snippet.snippet_folder
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND FOLDER_NM = #{folderNm}
   AND DEL_YN = 'N'

  AND FOLDER_NO != #{excludeFolderNo}

/* SnippetMapper.getTagDuplicateCount: 태그명 중복 건수를 조회 */
SELECT COUNT(*)
  FROM snippet.snippet_tag
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND TAG_NM = #{tagNm}
   AND DEL_YN = 'N'

  AND TAG_NO != #{excludeTagNo}

/* SnippetMapper.getMaxFolderSortSeq: 폴더 정렬순서 최대값을 조회 */
SELECT COALESCE(MAX(SORT_SEQ), 0)
  FROM snippet.snippet_folder
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND DEL_YN = 'N'

/* SnippetMapper.getMaxTagSortSeq: 태그 정렬순서 최대값을 조회 */
SELECT COALESCE(MAX(SORT_SEQ), 0)
  FROM snippet.snippet_tag
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND DEL_YN = 'N'

/* SnippetMapper.getSnippetCount: 스니펫 목록 총 건수를 조회 */
SELECT COUNT(DISTINCT base.SNIPPET_NO)
  FROM snippet.snippet_base base

/* SnippetMapper.getSnippetTagNoList: 스니펫에 연결된 태그 번호 목록을 조회 */
SELECT tag_map.TAG_NO
  FROM snippet.snippet_tag_map tag_map
  INNER JOIN snippet.snippet_tag tag
    ON tag.TAG_NO = tag_map.TAG_NO
   AND tag.SNIPPET_USER_NO = #{snippetUserNo}
   AND tag.DEL_YN = 'N'
 WHERE tag_map.SNIPPET_NO = #{snippetNo}
 ORDER BY tag.SORT_SEQ ASC, tag_map.TAG_NO ASC

mapper.insert:
/* SnippetMapper.insertSnippetBase: 신규 스니펫을 등록 */
INSERT INTO snippet.snippet_base (
       SNIPPET_USER_NO
     , FOLDER_NO
     , LANGUAGE_CD
     , TITLE
     , SUMMARY
     , SNIPPET_BODY
     , MEMO
     , IS_FAVORITE
     , BODY_HASH
     , DEL_YN
     , REG_NO
     , UDT_NO
) VALUES (
       #{snippetUserNo}
     , #{command.folderNo}
     , #{command.languageCd}
     , #{command.title}
     , #{command.summary}
     , #{command.snippetBody}
     , #{command.memo}
     , #{command.favoriteYn}
     , #{bodyHash}
     , 'N'
     , #{auditNo}
     , #{auditNo}
)

mapper.update:
/* SnippetMapper.updateSnippetBase: 기존 스니펫을 수정 */
UPDATE snippet.snippet_base
   SET FOLDER_NO = #{command.folderNo}
     , LANGUAGE_CD = #{command.languageCd}
     , TITLE = #{command.title}
     , SUMMARY = #{command.summary}
     , SNIPPET_BODY = #{command.snippetBody}
     , MEMO = #{command.memo}
     , IS_FAVORITE = #{command.favoriteYn}
     , BODY_HASH = #{bodyHash}
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND SNIPPET_NO = #{snippetNo}
   AND DEL_YN = 'N'

/* SnippetMapper.softDeleteSnippet: 스니펫을 소프트 삭제 */
UPDATE snippet.snippet_base
   SET DEL_YN = 'Y'
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND SNIPPET_NO = #{snippetNo}
   AND DEL_YN = 'N'

/* SnippetMapper.updateSnippetFavorite: 스니펫 즐겨찾기 여부를 갱신 */
UPDATE snippet.snippet_base
   SET IS_FAVORITE = #{favoriteYn}
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND SNIPPET_NO = #{snippetNo}
   AND DEL_YN = 'N'

/* SnippetMapper.updateSnippetLastCopiedDt: 스니펫 마지막 복사 일시와 복사 수를 갱신 */
UPDATE snippet.snippet_base
   SET COPY_CNT = COPY_CNT + 1
     , LAST_COPIED_DT = NOW()
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND SNIPPET_NO = #{snippetNo}
   AND DEL_YN = 'N'

/* SnippetMapper.updateSnippetLastViewedDt: 스니펫 마지막 조회 일시와 조회 수를 갱신 */
UPDATE snippet.snippet_base
   SET VIEW_CNT = VIEW_CNT + 1
     , LAST_VIEWED_DT = NOW()
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND SNIPPET_NO = #{snippetNo}
   AND DEL_YN = 'N'

mapper.delete:
/* SnippetMapper.deleteSnippetTagMapBySnippetNo: 스니펫 태그 매핑을 모두 제거 */
DELETE tag_map
  FROM snippet.snippet_tag_map tag_map
  INNER JOIN snippet.snippet_base base
    ON base.SNIPPET_NO = tag_map.SNIPPET_NO
 WHERE base.SNIPPET_USER_NO = #{snippetUserNo}
   AND tag_map.SNIPPET_NO = #{snippetNo}

