mapper.update:
/* SnippetMapper.updateSnippetFolder: 사용자 폴더를 수정 */
UPDATE snippet.snippet_folder
   SET FOLDER_NM = #{command.folderNm}
     , COLOR_HEX = #{command.colorHex}
     , SORT_SEQ = #{resolvedSortSeq}
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND FOLDER_NO = #{folderNo}
   AND DEL_YN = 'N'

/* SnippetMapper.softDeleteSnippetFolder: 사용자 폴더를 소프트 삭제 */
UPDATE snippet.snippet_folder
   SET DEL_YN = 'Y'
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND FOLDER_NO = #{folderNo}
   AND DEL_YN = 'N'

/* SnippetMapper.clearSnippetFolder: 폴더 삭제 전 연결 스니펫의 폴더를 해제 */
UPDATE snippet.snippet_base
   SET FOLDER_NO = NULL
     , UDT_NO = #{auditNo}
     , UDT_DT = NOW()
 WHERE SNIPPET_USER_NO = #{snippetUserNo}
   AND FOLDER_NO = #{folderNo}
   AND DEL_YN = 'N'

